import anthropic

client = anthropic.Anthropic()


def call(prompt: str, max_tokens: int = 350) -> str:
    return client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=max_tokens,
        temperature=0.0,
        messages=[{"role": "user", "content": prompt}],
    ).content[0].text.strip()


def cot_answer(question: str) -> str:
    return call(f"{question}\nLet's think step by step.")


def step_back_answer(question: str, abstract_q: str) -> str:
    principle = call(
        f"Answer this general question in 2 sentences:\n{abstract_q}"
    )
    return call(
        f"Principle: {principle}\n\n"
        f"Using this principle, answer concisely:\n{question}"
    )


# Questions where the two techniques should behave differently
TASKS = [
    {
        "question": "A train travels 120 km in 1.5 hours. What is its average speed?",
        "abstract_q": "What is the formula for calculating average speed?",
        "type": "arithmetic",
    },
    {
        "question": "Why does copper turn green when exposed to air and moisture over time?",
        "abstract_q": "What chemical reaction occurs when copper is exposed to oxygen and moisture?",
        "type": "factual/causal",
    },
    {
        "question": "If 30% of 200 students passed, how many failed?",
        "abstract_q": "How do you calculate a percentage of a total and find the remainder?",
        "type": "arithmetic",
    },
]

for task in TASKS:
    print(f"[{task['type']}] {task['question']}")
    print(f"CoT:        {cot_answer(task['question'])[:200]}")
    print(f"Step-back:  {step_back_answer(task['question'], task['abstract_q'])[:200]}")
    print()
